const query = $input.first().json.query || {};
const bonId = query.bon_id || '';
const token = query.token || '';

return [{
  json: {
    bon_id: bonId ? decodeURIComponent(bonId) : '',
    token
  }
}];

const baseUrl = $('Webhook Bon Production').first().json.headers?.host || 'localhost';
const query = $('Webhook Bon Production').first().json.query || {};
const bonId = query.bon_id || '';
let currentUrl = 'https://' + baseUrl + '/webhook/bon-production';
if (bonId) currentUrl += '?bon_id=' + encodeURIComponent(bonId);
const loginUrl = 'https://' + baseUrl + '/webhook/login?redirect_url=' + encodeURIComponent(currentUrl);
return [{json: {redirect_url: loginUrl}}];

const product = $('Search Product').first().json;
const params = $('Parse Parameters').first().json;
const userInfo = $('Search User By Token').first().json;
const token = params.token;
const bonId = params.bon_id;
const fmtIso = (s) => s ? s.replace(/\d{4}-\d{2}-\d{2}T[\d:.]+[+-]\d{2}:\d{2}/g, m => { const d = new Date(m); return isNaN(d) ? m : d.toLocaleDateString('fr-FR'); }) : s;
const baseUrl = $('Webhook Bon Production').first().json.headers?.host || 'localhost';

if (!product || !product.id) {
  const homeUrl = 'https://' + baseUrl + '/webhook/home?token=' + token;
  const html = '<html><head><meta charset="UTF-8"><title>Erreur</title></head><body style="font-family:sans-serif;background:#fff;display:flex;justify-content:center;align-items:center;min-height:100vh"><div style="text-align:center"><h1 style="color:#e74c3c">Produit non trouv\u00e9</h1><p>Le bon ' + fmtIso(bonId) + ' n\'existe pas ou n\'est pas valid\u00e9.</p><a href="' + homeUrl + '">Retour</a></div></body></html>';
  return [{json: {html}}];
}

const f = product.fields || product;
const invItem = $('Get Invoice').first().json;
const inv = invItem.fields || invItem;
const cliItem = $('Get Client').first().json;
const cli = cliItem.fields || cliItem;

const ETAPES_PAR_CATEGORIE = {
  'Store banne': ['D\u00e9coupe toile','Couture','D\u00e9coupe armature','Assemblage','R\u00e9glage','Emballage','Exp\u00e9dition'],
  'Lambrequin': ['D\u00e9coupe toile','Couture','Exp\u00e9dition'],
  'Rentoilage': ['D\u00e9coupe toile','Couture','Exp\u00e9dition'],
  'Rentoilage double pente': ['D\u00e9coupe toile','Couture','Exp\u00e9dition'],
  'Parasol': ['Exp\u00e9dition'],
  'Volet roulant': ['Envoy\u00e9 par email'],
  'Moustiquaire': ['Envoy\u00e9 par email']
};

const categorie = f.Categorie || '';
let effectiveCategorie = categorie;
if (categorie === 'Lambrequin') {
  try {
    const siblings = $('Fetch Sibling Products').all();
    const hasStore = siblings.some(item => {
      const sf = item.json.fields || item.json;
      return sf.Categorie === 'Store banne';
    });
    if (hasStore) effectiveCategorie = 'Store banne';
  } catch(e) {}
}

const etapes = ETAPES_PAR_CATEGORIE[effectiveCategorie] || ETAPES_PAR_CATEGORIE['Store banne'];

const stagesHtml = etapes.map(stage =>
  '<tr><td class="check-box">&#9744;</td><td class="stage-name">' + stage + '</td><td class="stage-sign"></td></tr>'
).join('');

// === Product fields ===
const qrCode = f.QR_Code || '';
const designation = f.Designation || 'N/A';
const productSummary = f.product_summary || '';
const accessories = f.accessories || '';
const largeur = f.Largeur_mm || '-';
const hauteur = f.Hauteur_mm || '-';
const avancee = f['avanc\u00e9e'] || f.avancee || '-';
const surface = f.Surface_m2 || '-';
const couleurToile = f.Couleur_toile || '-';
const couleurArmature = f.Couleur_armature || '-';
const moteur = f.Moteur || '-';
const lambrequin = f.Forme_lambrequin || '-';
const joncHaut = f.Jonc_haut || '-';
const joncBas = f.Jonc_bas || '-';
const capteurVent = f.Capteur_vent || '-';
const leds = f.LEDs || '-';
const options = f.Options_supplementaires || '-';
const typeCommande = f.Type_commande || '-';
const fixation = f.Accessoires_fixation || '-';
const kitScellement = f.Kit_scellement || '-';
const coteCommande = f.Cote_commande || '-';
const remarque = f.Remarque || '';
const selection = f.selection || '';
const prixTTC = f.Prix_total_TTC || '-';

// === Client / Invoice fields ===
const clientNom = cli.Nom || 'N/A';
const clientTel = cli['T\u00e9l\u00e9phone'] || cli.Telephone || '-';
const clientAdresse = cli.Adresse || '-';
const clientAdresseLiv = cli['Adresse livraison'] || cli.Adresse || '-';
const clientVille = cli.Ville || '-';
const clientCp = cli['Code postal'] || '-';
const factureNum = inv['Num\u00e9ro'] || inv['Num\u00e9ro facture'] || 'N/A';
const factureDate = (() => { const d = inv.Date; if (!d || d === '-') return '-'; const dt = new Date(d); return isNaN(dt) ? d : dt.toLocaleDateString('fr-FR'); })();
const magasin = inv.Magasin || '-';

const homeUrl = 'https://' + baseUrl + '/webhook/home?token=' + token;
const validationUrl = 'https://' + baseUrl + '/webhook/validation?bon_id=' + encodeURIComponent(bonId) + '&token=' + token;

// === Helper: only show spec row if value is not '-' and not empty ===
function specRow(label, value, full) {
  if (!value || value === '-') return '';
  const cls = full ? 'spec full' : 'spec';
  return '<div class="' + cls + '"><span class="lbl">' + label + '</span><span class="val">' + value + '</span></div>';
}

// Build specs HTML - only non-empty fields
let specsHtml = '';
specsHtml += specRow('D\u00e9signation', designation, true);
if (productSummary) specsHtml += specRow('R\u00e9sum\u00e9 produit', productSummary, true);
specsHtml += specRow('Cat\u00e9gorie', categorie, false);
specsHtml += specRow('Largeur', largeur !== '-' ? largeur + ' mm' : '', false);
specsHtml += specRow('Hauteur', hauteur !== '-' ? hauteur + ' mm' : '', false);
specsHtml += specRow('Avanc\u00e9e', avancee !== '-' ? avancee + ' mm' : '', false);
specsHtml += specRow('Surface', surface !== '-' ? surface + ' m\u00b2' : '', false);
specsHtml += specRow('Couleur toile', couleurToile, true);
specsHtml += specRow('Couleur armature', couleurArmature, false);
specsHtml += specRow('Moteur', moteur, false);
specsHtml += specRow('Type commande', typeCommande, false);
specsHtml += specRow('Lambrequin', lambrequin, false);
specsHtml += specRow('Jonc haut', joncHaut, false);
specsHtml += specRow('Jonc bas', joncBas, false);
specsHtml += specRow('Capteur vent', capteurVent, false);
specsHtml += specRow('LEDs', leds, false);
specsHtml += specRow('C\u00f4t\u00e9 commande', coteCommande, false);
specsHtml += specRow('Kit scellement', kitScellement, false);

// Fixation section (full width, important)
if (fixation && fixation !== '-') {
  specsHtml += '<div class="spec full fixation-highlight"><span class="lbl">Fixation</span><span class="val">' + fixation.replace(/\n/g, '<br>') + '</span></div>';
}

// Accessories
if (accessories) {
  specsHtml += '<div class="spec full"><span class="lbl">Accessoires</span><span class="val">' + accessories.replace(/\n/g, '<br>') + '</span></div>';
}

// Options
if (options && options !== '-') {
  specsHtml += '<div class="spec full"><span class="lbl">Options</span><span class="val">' + options.replace(/\n/g, '<br>') + '</span></div>';
}

// Selection
if (selection) {
  specsHtml += '<div class="spec full"><span class="lbl">S\u00e9lection</span><span class="val">' + selection.replace(/\n/g, '<br>') + '</span></div>';
}

const html = `<!DOCTYPE html>
<html lang="fr">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Bon de Production - ${fmtIso(bonId)}</title>
<style>
*{box-sizing:border-box;margin:0;padding:0}
body{font-family:'Segoe UI',Arial,sans-serif;background:#fff;color:#222;font-size:11pt;line-height:1.4}
.no-print{background:#f5f5f5;padding:12px 20px;display:flex;gap:12px;align-items:center;border-bottom:2px solid #ddd}
.no-print a,.no-print button{padding:8px 18px;border-radius:6px;font-size:0.9rem;text-decoration:none;cursor:pointer;font-weight:600;border:none;display:inline-flex;align-items:center;gap:6px}
.btn-print{background:#2563eb;color:#fff}
.btn-print:hover{background:#1d4ed8}
.btn-back{background:#e5e7eb;color:#333}
.btn-back:hover{background:#d1d5db}
.page{max-width:297mm;margin:0 auto;padding:10mm 12mm 8mm}
.header{display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:12px;padding-bottom:10px;border-bottom:3px solid #222}
.header-left h1{font-size:18pt;font-weight:800;color:#222;letter-spacing:-0.5px}
.header-left .subtitle{font-size:9pt;color:#666;margin-top:2px}
.header-right{text-align:right}
.header-right .bon-id{font-size:14pt;font-weight:800;color:#2563eb;font-family:monospace}
.header-right .date-info{font-size:9pt;color:#666;margin-top:2px}
.top-row{display:flex;gap:16px;margin-bottom:14px}
.qr-block{flex:0 0 120px;text-align:center}
.qr-block img{width:110px;height:110px;border:1px solid #ddd;border-radius:4px;padding:4px;background:#fff}
.qr-block .qr-label{font-size:7pt;color:#888;margin-top:3px}
.info-block{flex:1;display:grid;grid-template-columns:1fr 1fr 1fr 1fr;gap:6px 16px}
.info-item{display:flex;gap:6px}
.info-item .lbl{font-size:8pt;color:#666;min-width:55px;text-transform:uppercase;letter-spacing:0.3px}
.info-item .val{font-size:10pt;font-weight:600}
.section{margin-bottom:12px}
.section-title{font-size:10pt;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:#fff;background:#222;padding:5px 10px;margin-bottom:8px}
.two-col{display:flex;gap:16px;margin-bottom:12px}
.two-col>.section{flex:1;margin-bottom:0}
.two-col>.section:first-child{flex:3}
.two-col>.section:last-child{flex:2}
.specs-grid{display:grid;grid-template-columns:1fr 1fr 1fr;gap:4px 12px}
.spec{display:flex;gap:4px;padding:3px 0;border-bottom:1px dotted #ddd}
.spec.full{grid-column:1/-1}
.spec .lbl{font-size:8pt;color:#666;min-width:100px;text-transform:uppercase}
.spec .val{font-size:10pt;font-weight:600;flex:1}
.fixation-highlight{background:#e8f4fd;border:1px solid #90caf9;border-radius:4px;padding:6px 10px!important;margin:4px 0}
.fixation-highlight .lbl{color:#1565c0;font-weight:700}
.remark-box{background:#fff8e1;border:1px solid #ffc107;border-radius:4px;padding:8px 10px;margin-top:6px}
.remark-box .lbl{font-size:8pt;color:#e65100;font-weight:700;text-transform:uppercase}
.remark-box .val{font-size:10pt;margin-top:2px;white-space:pre-line}
.stages-table{width:100%;border-collapse:collapse}
.stages-table th{font-size:8pt;text-transform:uppercase;color:#666;letter-spacing:0.3px;padding:4px 8px;border-bottom:2px solid #222;text-align:left}
.stages-table td{padding:8px;border-bottom:1px solid #eee;font-size:10pt}
.check-box{width:28px;font-size:16pt;text-align:center;color:#bbb}
.stage-name{font-weight:600}
.stage-sign{width:140px;border-bottom:1px dotted #ccc}
.delivery{display:grid;grid-template-columns:1fr 1fr;gap:4px 16px}
.delivery .spec{border-bottom:none;padding:2px 0}
.footer-print{margin-top:16px;padding-top:8px;border-top:2px solid #222;display:flex;justify-content:space-between;font-size:8pt;color:#888}
@media print{
  .no-print{display:none!important}
  body{background:#fff}
  .page{padding:10mm;margin:0}
  @page{size:A4 landscape;margin:5mm}
}
@media(max-width:768px){
  .page{padding:10px}
  .two-col{flex-direction:column}
  .specs-grid{grid-template-columns:1fr 1fr}
  .top-row{flex-direction:column;align-items:center}
  .info-block{grid-template-columns:1fr 1fr}
  .no-print{flex-wrap:wrap}
}
@media(max-width:480px){
  .specs-grid{grid-template-columns:1fr}
  .delivery{grid-template-columns:1fr}
  .info-block{grid-template-columns:1fr}
  .header{flex-direction:column;gap:8px}
  .header-right{text-align:left}
}
</style>
</head>
<body>
<div class="no-print">
  <button class="btn-print" onclick="window.print()">&#128424; Imprimer</button>
  <a class="btn-back" href="${validationUrl}">&larr; Validation</a>
  <a class="btn-back" href="${homeUrl}">Accueil</a>
</div>
<div class="page">
  <div class="header">
    <div class="header-left">
      <h1>BON DE PRODUCTION</h1>
      <div class="subtitle">MON USINE</div>
    </div>
    <div class="header-right">
      <div class="bon-id">${fmtIso(bonId)}</div>
      <div class="date-info">Facture ${factureNum} du ${factureDate}</div>
    </div>
  </div>

  <div class="top-row">
    ${qrCode ? '<div class="qr-block"><img src="' + qrCode + '" alt="QR"/><div class="qr-label">Scanner pour suivi</div></div>' : ''}
    <div class="info-block">
      <div class="info-item"><span class="lbl">Client</span><span class="val">${clientNom}</span></div>
      <div class="info-item"><span class="lbl">T&eacute;l</span><span class="val">${clientTel}</span></div>
      <div class="info-item"><span class="lbl">Magasin</span><span class="val">${magasin}</span></div>
      <div class="info-item"><span class="lbl">Prix TTC</span><span class="val">${prixTTC} &euro;</span></div>
    </div>
  </div>

  <div class="two-col">
  <div class="section">
    <div class="section-title">Sp&eacute;cifications Produit</div>
    <div class="specs-grid">
      ${specsHtml}
    </div>
    ${remarque ? '<div class="remark-box"><div class="lbl">&#9888; Remarque</div><div class="val">' + remarque.replace(/\n/g, '<br>') + '</div></div>' : ''}
  </div>

  <div class="section">
    <div class="section-title">&Eacute;tapes de Production</div>
    <table class="stages-table">
      <thead><tr><th></th><th>&Eacute;tape</th><th>Signature / Date</th></tr></thead>
      <tbody>${stagesHtml}</tbody>
    </table>
  </div>
  </div>

  <div class="section">
    <div class="section-title">Livraison</div>
    <div class="delivery">
      <div class="spec full"><span class="lbl">Adresse</span><span class="val">${clientAdresseLiv}</span></div>
      <div class="spec"><span class="lbl">CP / Ville</span><span class="val">${clientCp} ${clientVille}</span></div>
    </div>
  </div>

  <div class="footer-print">
    <span>MON USINE - Bon de production</span>
    <span>${fmtIso(bonId)} | ${factureNum}</span>
    <span>Imprim&eacute; le ${new Date().toLocaleDateString('fr-FR')}</span>
  </div>
</div>
</body>
</html>`;

return [{json: {html}}];
